package session

type State string

const (
	StateWorking State = "working"
	StatePrompt  State = "prompt"
	StateTriage  State = "triage"
	StateDone    State = "done"
)

type Session struct {
	AttachCommand     []string `json:"-"`
	Agent             string   `json:"agent"`
	AgentPluginID     string   `json:"agentPluginId"`
	CWD               string   `json:"cwd"`
	Description       string   `json:"description"`
	ID                string   `json:"id"`
	Issue             string   `json:"issue"`
	Kind              string   `json:"kind"`
	Metadata          string   `json:"metadata"`
	PipePath          string   `json:"-"`
	Project           string   `json:"project"`
	RuntimeKind       string   `json:"runtimeKind,omitempty"`
	RuntimeTarget     string   `json:"runtimeTarget,omitempty"`
	Selected          bool     `json:"selected,omitempty"`
	State             State    `json:"state"`
	TerminalKey       string   `json:"-"`
	TerminalSupported bool     `json:"terminalSupported"`
	Title             string   `json:"title"`
	WorkerID          string   `json:"workerId"`
}

type Project struct {
	ID   string `json:"id"`
	Name string `json:"name"`
}

type Workspace struct {
	ActiveProjectID string    `json:"activeProjectId"`
	Orchestrators   []Session `json:"orchestrators,omitempty"`
	Projects        []Project `json:"projects"`
	Sessions        []Session `json:"sessions"`
}

func (w Workspace) Session(id string) (Session, bool) {
	for _, session := range w.Sessions {
		if session.ID == id {
			return session, true
		}
	}

	return Session{}, false
}

func (w Workspace) ProjectSession(projectID string, id string) (Session, bool) {
	for _, session := range w.Sessions {
		if session.Project == projectID && session.ID == id {
			return session, true
		}
	}

	return Session{}, false
}

