  const fallbackSession = getSelectedWorkerSession(sessions);
  const nextSelectedSessionKey = sessions.some(
    (session) => getWorkerSessionSelectionKey(session) === selectedSessionKey
  )
    ? selectedSessionKey
    : fallbackSession
