      }

      try {
        const parsed = JSON.parse(payload) as {
          cols?: unknown;
          rows?: unknown;
          type?: unknown;
        };

        return (
          parsed.type === 'resize' &&
          typeof parsed.cols === 'number' &&
          parsed.cols > 0 &&
          typeof parsed.rows === 'number' &&
          parsed.rows > 0
        );
      } catch {
        return false;
      }
    });
  });
}

