        return [];
      }

      try {
        const parsed = JSON.parse(payload) as {
          cols?: unknown;
          rows?: unknown;
          type?: unknown;
        };

        if (
          parsed.type !== 'resize' ||
          typeof parsed.cols !== 'number' ||
          typeof parsed.rows !== 'number'
